export type TerminalProsodyMode = 'off' | 'observe' | 'bias';

/**
 * Parses the Terminal Prosody Mode.
 */
export function parseTerminalProsodyMode(
  value: string | undefined,
  warn: (message: string) => void = console.warn,
): TerminalProsodyMode {
  const normalized = value?.trim().toLowerCase();
  if (!normalized) {
    // DEFAULT OFF until the prosody-speed work lands. Terminal-prosody biasing
    // is catastrophically slow on CPU (~15-19s/step x 100-200 steps = ~30-50min
    // per chat completion), so it is opt-in only — never triggered by an unset
    // env. Voice/TTS callers opt in explicitly via the request `enable_prosody`
    // field; the env can still force it on globally with TERMINAL_PROSODY=bias.
    // Flip this default back to 'bias' (or remove the gate) once the algorithm
    // speedup makes prosody cheap enough to be on by default.
    return 'off';
  }
  if (
    normalized === '0' ||
    normalized === 'false' ||
    normalized === 'off' ||
    normalized === 'disable' ||
    normalized === 'disabled' ||
    normalized === 'no'
  ) {
    return 'off';
  }
  if (normalized === 'observe' || normalized === 'telemetry') {
    return 'observe';
  }
  if (
    normalized === '1' ||
    normalized === 'true' ||
    normalized === 'on' ||
    normalized === 'bias' ||
    normalized === 'enabled' ||
    normalized === 'yes'
  ) {
    return 'bias';
  }
  warn(
    `[openai-server] unknown TERMINAL_PROSODY=${value}; expected off, observe, or bias; disabling`,
  );
  return 'off';
}
